# ===== amalgamated from cordon/detect/validators.py =====
# Canonical placeholder-token union.
_PLACEHOLDER_TOKENS = (
    "EXAMPLE", "XXXX", "000000", "your-", "YOUR-", "REPLACE", "redacted", "REDACTED",
)
_SEQUENTIAL = re.compile(r"123456|234567|345678|456789|567890|abcdef|ABCDEF")
_REPEATED = re.compile(r"(.)\1{5,}")

# Real issuer prefixes -- a Luhn-valid run without one is almost never a card.
_CARD_IIN = re.compile(
    r"^(?:4|5[1-5]|2(?:2[2-9]|[3-6]\d|7[01]|720)|3[47]|6011|65|64[4-9]|35\d\d|30[0-5]|3[689])"
)

# Canonical test PANs -- never flagged (payment docs / fixtures use them).
TEST_CARDS = frozenset({
    "4111111111111111", "4012888888881881", "4242424242424242", "5555555555554444",
    "5105105105105100", "2223003122003222", "378282246310005", "371449635398431",
    "6011111111111117", "6011000990139424", "3530111333300000", "3566002020360505",
    "30569309025904", "38520000023237",
})

ENTROPY_BITS_MIN = 4.0


def is_placeholder(text: str, mode: str = "full") -> bool:
    """True if a matched value is an obvious placeholder / documented test vector.

    mode="full" (write / CI paths): union tokens + sequential + repeated-char heuristics
      -- byte-faithful to scan_secrets.py and dlp_fingerprint_scan.py.
    mode="tokens" (redact path): union tokens ONLY, no sequential/repeat heuristic --
      byte-faithful to redact_tool_output.py, and the safe (over-mask) direction for a
      redactor: a real secret whose body happens to contain "123456" or a 6+ run is still
      masked instead of leaking.
    """
    if any(tok in text for tok in _PLACEHOLDER_TOKENS):
        return True
    if mode == "tokens":
        return False
    if _SEQUENTIAL.search(text):
        return True
    if _REPEATED.search(text):
        return True
    return False


def valid_ssn(m: str) -> bool:
    """``m`` == 'ddd-dd-dddd'. Reject reserved area/group/serial to cut false hits."""
    area, group, serial = m[:3], m[4:6], m[7:11]
    if area in ("000", "666") or area[0] == "9":
        return False
    return group != "00" and serial != "0000"


def luhn_ok(digits: str) -> bool:
    """Luhn checksum over a string of digits (no separators)."""
    total, parity = 0, len(digits) % 2
    for i, ch in enumerate(digits):
        d = ord(ch) - 48
        if i % 2 == parity:
            d *= 2
            if d > 9:
                d -= 9
        total += d
    return total % 10 == 0


def looks_like_card(digits: str) -> bool:
    """``digits`` already stripped of separators. Length + issuer-prefix + Luhn."""
    if len(digits) not in (13, 14, 15, 16, 19):
        return False
    if not _CARD_IIN.match(digits):
        return False
    return luhn_ok(digits)


def shannon_bits(s: str) -> float:
    """Shannon entropy in bits per character."""
    if not s:
        return 0.0
    n = len(s)
    return -sum((c / n) * math.log2(c / n) for c in Counter(s).values())

