@dataclass(frozen=True)
class Detector:
    id: str
    cls: str
    human_label: str
    machine_tag: str
    severity: str            # "high" | "medium" | "low"
    default_action: str      # hint only -- policy matrix decides per surface
    high_confidence: bool    # eligible for input-blocking (prompt) hooks
    redactable: bool         # masked by redact() (entropy is not)
    suppress_placeholder: bool = True
