# --- secret key / PEM shapes: content-wide, high-confidence, block -----------
# (id, regex, human_label, machine_tag)
#
# AWS keys (AKIA/ASIA) use a CLASS lookbehind/lookahead instead of \b. That is the H1 fix
# (SECURITY_MODEL.md "Known gaps"): the old \bAKIA...{16}\b anchor failed on a key abutting a
# word char with no delimiter ("prefix"+key), and the fixed-length quantifier could not
# backtrack -> zero findings -> the guard ALLOWed the raw key (a HIGH leak). AWS bodies are
# UPPERCASE-only ([0-9A-Z]), so (?<![A-Z0-9])AKIA[0-9A-Z]{16}(?![0-9A-Z]) admits a lowercase-
# adjacent prefix (closing the leak) while still refusing an over-long all-caps blob -- verified
# ZERO realistic false positives.
#
# github/slack/google ALSO drop the leading \b (google drops the TRAILING \b too: fixed {35}\b
# failed when the 39-char key abutted a following alnum, a second leak). These prefixes are
# DISTINCTIVE (gh[pousr]_ / xox[baprs]- / AIza), so a bare form is a strict SUPERSET of the \b
# form -- it can only ADD matches (over-detect is the safe redactor direction), never leak, with
# zero realistic false positives: a snake/kebab identifier cannot reach the required UNBROKEN body
# length after the distinctive prefix (verified).
#
# sk-/sk_live_ DELIBERATELY keep \b (the H1 RESIDUAL). Their prefix is a substring of common
# tokens AND their body admits the chars that let those reach the min length, so dropping \b would
# false-positive: sk-...{32,} matches inside "task-"/"risk-" and sk_live_ inside "task_live_..."
# (real FPs, verified). A real sk-/sk_live_ key sits after =/:/quote/space -- all still caught by
# \b -- so the residual is only the contrived no-delimiter case. Tracked in SECURITY_MODEL.md +
# an xfail in tests/golden/test_known_gaps.py.
_SECRET_SPECS: List[Tuple[str, str, str, str]] = [
    ("aws_access_key", r"(?<![A-Z0-9])AKIA[0-9A-Z]{16}(?![0-9A-Z])", "AWS access key", "AWS-KEY"),
    ("aws_session_token", r"(?<![A-Z0-9])ASIA[0-9A-Z]{16}(?![0-9A-Z])", "AWS session token", "AWS-TOKEN"),
    ("github_token", r"gh[pousr]_[A-Za-z0-9]{36,}\b", "GitHub token", "GITHUB-TOKEN"),
    ("slack_token", r"xox[baprs]-[A-Za-z0-9-]{10,}\b", "Slack token", "SLACK-TOKEN"),
    ("openai_anthropic_key", r"\bsk-[A-Za-z0-9_-]{32,}\b", "OpenAI/Anthropic-style key", "API-KEY"),
    ("google_api_key", r"AIza[0-9A-Za-z_-]{35}", "Google API key", "GOOGLE-KEY"),
    ("stripe_live_key", r"\bsk_live_[0-9A-Za-z]{24,}\b", "Stripe live key", "STRIPE-KEY"),
]

SECRET_DETECTORS: List[Detector] = [
    Detector(
        id=_id, cls=SECRET, human_label=hl, machine_tag=mt,
        severity="high", default_action=BLOCK,
        high_confidence=True, redactable=True, suppress_placeholder=True,
        regex=re.compile(rx),
    )
    for (_id, rx, hl, mt) in _SECRET_SPECS
]

# --- PEM private key: bounded finder (fixes truncated-body leak + ReDoS) ------
# A single regex with an optional/lazy END group leaks the body on a BEGIN-without-END
# block (match collapses to the marker) and backtracks quadratically on many-BEGIN input.
# Instead: find each BEGIN, then locate END within a bounded window (search with endpos,
# O(1) advance). When END is absent, mask BEGIN..EOF within the cap -- over-mask is the
# safe direction for a redactor.
_PEM_BEGIN_RE = re.compile(r"-----BEGIN (?:RSA |EC |OPENSSH |DSA |PGP )?PRIVATE KEY-----")
_PEM_END_RE = re.compile(r"-----END (?:RSA |EC |OPENSSH |DSA |PGP )?PRIVATE KEY-----")
_PEM_MAX = 65536  # cap the body scan; larger than any real single PEM private key


def _pem_finder(text: str) -> Iterator[Tuple[str, int, int]]:
    pos, n = 0, len(text)
    while True:
        b = _PEM_BEGIN_RE.search(text, pos)
        if b is None:
            return
        e = _PEM_END_RE.search(text, b.end(), min(n, b.end() + _PEM_MAX))
        end = e.end() if e is not None else min(n, b.end() + _PEM_MAX)
        yield text[b.start():end], b.start(), end
        pos = end


PEM_DETECTOR = Detector(
    id="private_key_block", cls=SECRET, human_label="Private key block",
    machine_tag="PRIVATE-KEY", severity="high", default_action=BLOCK,
    high_confidence=True, redactable=True,
    suppress_placeholder=False,  # a BEGIN/END-delimited block is never a placeholder
    finder=_pem_finder,
)

# --- SSN: regex + reserved-range validation ----------------------------------
SSN_DETECTOR = Detector(
    id="us_ssn", cls=PII, human_label="US SSN", machine_tag="US-SSN",
    severity="medium", default_action=BLOCK,
    high_confidence=True, redactable=True, suppress_placeholder=True,
    regex=re.compile(r"\b\d{3}-\d{2}-\d{4}\b"), validate=valid_ssn,
)

# --- payment card: boundary-aligned candidate scan + Luhn/IIN/test-card exclusion ---
# A PAN is 13-19 digits, optionally split into groups by single spaces or hyphens
# ("4111 1111 1111 1111"). Within each maximal digit+separator run, candidates are formed
# only from WHOLE separator-delimited groups (a group-boundary-aligned window) -- never
# mid-group -- so a Luhn-valid sub-run of a single long number is not isolated (the false
# positive a naive per-digit slide caused). The outer index advances ONE group at a time and
# emits the LONGEST valid window at each start, so windows may OVERLAP by design. LONGEST (not
# shortest) is load-bearing: a real PAN starting at group boundary a always has [a..PAN-end]
# valid, so the longest-at-a window is a SUPERSET of the PAN -- it can never truncate a 19-digit
# PAN to a coincidentally-Luhn-valid leading-16 window and strand the tail (that was a ~10% leak
# on the standard 4-4-4-4-3 grouping, a regression vs the greedy originals, before this fix).
# For this superset guarantee to hold, the TEST_CARDS branch below must `continue`, NOT `break`:
# a `break` at a group-aligned test-card leading window abandons the longer real window from the
# same start (leaking the PAN, round-5 finding A) and leaves a staged prefix emitted (round-5
# finding B). It discards the staged prefix and keeps extending instead.
# Overlap also handles adjacency: when a spurious <numeric-prefix + partial-PAN> window and the
# real PAN's own window overlap, redact()'s _mask_spans masks the TAIL of the later span, so no
# PAN digit escapes (over-masking the prefix is the safe redactor direction). This isolates a
# PAN beside another space/hyphen group (card+SSN, number+card, card+card) that the four greedy
# originals merged into an over-length blob and LEAKED. Pre-launch severity LOW/MEDIUM.
# ACCEPTED, documented limitations (safe over-mask direction, NOT defects):
#   - a long NON-card number in 4-4-... groups may present a group-aligned 13-19-digit window
#     that coincidentally passes Luhn+IIN (~5% of random 20-digit 4x4 strings) -> an OVER-mask,
#     never a leak;
#   - scan() may return MULTIPLE overlapping CARD findings for one region -- over-detection,
#     not a defect;
#   - two PANs GLUED with no separator are one group with no split boundary -> still missed
#     (the four originals miss them too);
#   - group separators OTHER than space/hyphen (comma/tab/newline/slash) are not spanned --
#     inherited verbatim from the four originals' [ -] class, so not a new leak.
# The '.' is excluded from the run body but NOT the boundary lookarounds: a PAN abutting a
# period (sentence end / decimal / filename) must still form a run. looks_like_card's
# length+IIN+Luhn gate -- not a '.' in the lookaround -- is what suppresses decimals.
_CARD_RUN = re.compile(r"(?<!\d)[0-9](?:[0-9 \-]*[0-9])?(?!\d)")
_CARD_GROUP = re.compile(r"[0-9]+")
_CARD_MIN, _CARD_MAX = 13, 19  # looks_like_card enforces the exact valid-length set within


def _card_finder(text: str) -> Iterator[Tuple[str, int, int]]:
    for run in _CARD_RUN.finditer(text):
        base = run.start()
        groups = [(base + g.start(), base + g.end(), g.end() - g.start())
                  for g in _CARD_GROUP.finditer(run.group(0))]
        ng = len(groups)
        for i in range(ng):  # advance ONE group at a time; windows may overlap (see above)
            total = 0
            best = None  # LONGEST valid window from this start (a shorter, coincidentally
            for j in range(i, ng):  # valid prefix must NOT be emitted alone -- it strands a tail)
                total += groups[j][2]
                if total > _CARD_MAX:
                    break
                if total < _CARD_MIN:
                    continue
                start, end = groups[i][0], groups[j][1]
                digits = text[start:end].replace(" ", "").replace("-", "")
                if digits in TEST_CARDS:
                    # This window IS a canonical test PAN. Discard any shorter valid window
                    # already staged (at a fixed start all windows nest, so it is a proper
                    # PREFIX of this test PAN -- test material, never real cardholder data;
                    # emitting it was round-5 finding B) AND keep extending, do NOT break: a
                    # longer real PAN can start here whose group-aligned leading window equals
                    # a test card (a 19-digit PAN with a test-card leading 16). `break` here
                    # abandoned that longer window and leaked all 19 digits raw (round-5
                    # finding A) -- it defeated the longest-per-start superset guarantee below.
                    best = None
                    continue
                if looks_like_card(digits):
                    best = (start, end)  # keep scanning: prefer the longest valid window
            if best is not None:
                yield text[best[0]:best[1]], best[0], best[1]


CARD_DETECTOR = Detector(
    id="payment_card", cls=PCI, human_label="Payment card (PCI)", machine_tag="CARD",
    severity="high", default_action=BLOCK,
    high_confidence=True, redactable=True,
    suppress_placeholder=False,  # excluded only via TEST_CARDS, never placeholder heuristics
    finder=_card_finder,
)

# --- keyword-gated high-entropy secret ---------------------------------------
_ENTROPY_ASSIGN = re.compile(
    r"(?i)\b(?:secret|token|passwd|password|api[_-]?key|apikey|"
    r"access[_-]?key|auth[_-]?token|client[_-]?secret)\b"
    r"\s*[:=]\s*['\"]?([A-Za-z0-9+/_\-]{20,})['\"]?"
)


def _entropy_finder(text: str) -> Iterator[Tuple[str, int, int]]:
    for m in _ENTROPY_ASSIGN.finditer(text):
        val = m.group(1)
        if shannon_bits(val) >= ENTROPY_BITS_MIN:
            yield val, m.start(1), m.end(1)


# Not high-confidence (kept out of prompt-blocking hooks) and NOT redactable
# (masking every high-entropy string would corrupt SHAs / UUIDs / base64 blobs).
ENTROPY_DETECTOR = Detector(
    id="high_entropy_secret", cls=SECRET, human_label="High-entropy secret",
    machine_tag="HIGH-ENTROPY", severity="medium", default_action=BLOCK,
    high_confidence=False, redactable=False, suppress_placeholder=True,
    finder=_entropy_finder,
)

ALL_DETECTORS: List[Detector] = [
    *SECRET_DETECTORS, PEM_DETECTOR, SSN_DETECTOR, CARD_DETECTOR, ENTROPY_DETECTOR,
]
HIGH_CONFIDENCE: List[Detector] = [d for d in ALL_DETECTORS if d.high_confidence]
REDACTABLE: List[Detector] = [d for d in ALL_DETECTORS if d.redactable]


def by_class(*classes: str) -> List[Detector]:
    """Detectors whose class is in ``classes`` (e.g. ``by_class(SECRET, PCI)``)."""
    want = set(classes)
    return [d for d in ALL_DETECTORS if d.cls in want]

# ===== amalgamated from cordon/detect/scan.py =====
_PREVIEW_LEN = 4


@dataclass(frozen=True)
class Finding:
    detector_id: str
    cls: str
    label: str       # human-readable label
    tag: str         # machine tag (used by redaction markers)
    start: int
    end: int
    severity: str
    preview: str     # short, non-reversible; never the full matched value


def _preview(cls: str, value: str) -> str:
    # Preview allowlist: ONLY secrets get a short type-hint prefix; every other class
    # (PII/PCI/PHI/IP and any unknown/future class) returns "" -- fail closed.
    if cls != patterns.SECRET:
        return ""
    return value[:_PREVIEW_LEN] + "..." if len(value) > _PREVIEW_LEN else value


def _mk(det: Detector, value: str, start: int, end: int) -> Finding:
    return Finding(
        detector_id=det.id,
        cls=det.cls,
        label=det.human_label,
        tag=det.machine_tag,
        start=start,
        end=end,
        severity=det.severity,
        preview=_preview(det.cls, value),
    )


def scan(
    text: str,
    detectors: Optional[Iterable[Detector]] = None,
    placeholder_mode: str = "full",
) -> List[Finding]:
    """Return every detector match over ``text``, sorted by offset.

    ``detectors`` defaults to :data:`patterns.ALL_DETECTORS`; pass a subset such as
    :data:`patterns.HIGH_CONFIDENCE` or :data:`patterns.REDACTABLE` to scope detection.
    ``placeholder_mode`` is forwarded to :func:`is_placeholder` for detectors that
    suppress placeholders: "full" (write/CI paths) or "tokens" (redact path).
    """
    if not text:
        return []
    dets = list(detectors) if detectors is not None else patterns.ALL_DETECTORS
    findings: List[Finding] = []
    for det in dets:
        if det.finder is not None:
            for value, start, end in det.finder(text):
                if det.suppress_placeholder and is_placeholder(value, placeholder_mode):
                    continue
                findings.append(_mk(det, value, start, end))
        elif det.regex is not None:
            for m in det.regex.finditer(text):
                value = m.group(0)
                if det.suppress_placeholder and is_placeholder(value, placeholder_mode):
                    continue
                # The validator runs on EVERY path, including redact (placeholder_mode
                # "tokens"). For SSN this is an intentional canonical delta: reserved-range
                # shapes (SSA-never-issued) are not masked, unlike redact_tool_output.py which
                # masked any ddd-dd-dddd. Safe -- reserved ranges are not real SSNs and a
                # valid SSN is still masked. Matches 3 of the 4 originals. Locked by
                # test_redact_reserved_range_ssn_not_masked_documented_delta.
                if det.validate is not None and not det.validate(value):
                    continue
                findings.append(_mk(det, value, m.start(), m.end()))
    findings.sort(key=lambda f: (f.start, f.end))
    return findings

# ===== shim: restore patterns.X attribute access after flattening =====
patterns = types.SimpleNamespace(
    SECRET=SECRET, PII=PII, PCI=PCI, PHI=PHI, IP=IP,
    ALL_DETECTORS=ALL_DETECTORS, HIGH_CONFIDENCE=HIGH_CONFIDENCE,
    REDACTABLE=REDACTABLE,
)

# --- hook shell: scan_prompt_dlp (UserPromptSubmit) ---------------------------
# stdin: {"prompt": "..."}; exit 2 blocks the submit and shows stderr to the user; exit 0
# lets it through. High-confidence shapes only (secrets/PEM/SSN/card, NOT entropy) -- the
# same detector subset the library's HIGH_CONFIDENCE list selects. Escape hatches match the
# hand-written hook: DLP_ALLOW_PROMPT_SECRETS=1 or a literal 'dlp-ok' token in the prompt.
def main() -> int:
    if os.environ.get("DLP_ALLOW_PROMPT_SECRETS", "").strip() in ("1", "true", "yes"):
        return 0
    try:
        data = json.load(sys.stdin)
    except json.JSONDecodeError:
        return 0
    prompt = data.get("prompt", "")
    if not prompt or "dlp-ok" in prompt:
        return 0
    labels = sorted({f.label for f in scan(prompt, HIGH_CONFIDENCE)})
    if labels:
        print(
            "BLOCKED (prompt DLP): your prompt appears to contain "
            + ", ".join(labels)
            + ". Sending it would put the value into the model context, transcript, and "
            "logs. Redact it and resubmit -- or set DLP_ALLOW_PROMPT_SECRETS=1 / include "
            "'dlp-ok' to override.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
